import{_ as e,o,c as a,ag as r}from"./chunks/framework.BD8VCRzL.js";const c=JSON.parse('{"title":"Setup Guide","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/setup.md","filePath":"getting-started/setup.md"}'),s={name:"getting-started/setup.md"};function i(n,t,l,u,h,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="setup-guide" tabindex="-1">Setup Guide <a class="header-anchor" href="#setup-guide" aria-label="Permalink to &quot;Setup Guide&quot;">​</a></h1><p>This guide walks you through creating your account and logging your first trade.</p><h2 id="creating-your-account" tabindex="-1">Creating Your Account <a class="header-anchor" href="#creating-your-account" aria-label="Permalink to &quot;Creating Your Account&quot;">​</a></h2><p><strong>Step 1:</strong> Open the app in your browser. You will see a sign-in page with options to sign in or create an account.</p><p><strong>Step 2:</strong> Click &quot;Create Account&quot; or the sign-up link.</p><p><strong>Step 3:</strong> Enter your email and choose a password. That&#39;s it — no verification steps or extra info needed.</p><p><strong>Step 4:</strong> After creating your account, you are automatically signed in and taken to your dashboard.</p><div class="info custom-block"><p class="custom-block-title">What Happens to Your Data</p><p>Your data is stored securely and associated with your account. It is only used to power your dashboard and insights. The AI does not share your trading data with anyone.</p></div><h2 id="your-first-look-at-the-dashboard" tabindex="-1">Your First Look at the Dashboard <a class="header-anchor" href="#your-first-look-at-the-dashboard" aria-label="Permalink to &quot;Your First Look at the Dashboard&quot;">​</a></h2><p>When you first log in, the dashboard is empty. You will see:</p><ul><li><strong>A header</strong> with your name and a &quot;Sign Out&quot; button</li><li><strong>A large P&amp;L chart</strong> — currently showing a placeholder because you have no trades yet</li><li><strong>Two smaller charts</strong> — Discipline Score and Agency Score, also empty</li><li><strong>An Insights panel</strong> — prompting you to log trades to unlock insights</li><li><strong>A text box at the bottom</strong> — this is where you log trades</li></ul><p>The dashboard is designed so you can see everything at a glance. No clicking around to check your session.</p><h2 id="logging-your-first-trade" tabindex="-1">Logging Your First Trade <a class="header-anchor" href="#logging-your-first-trade" aria-label="Permalink to &quot;Logging Your First Trade&quot;">​</a></h2><p><strong>Step 1:</strong> Look at the bottom of your screen. You will see a text input that says something like:</p><blockquote><p>&quot;Describe your trade (e.g., &#39;Long NQ at 17800, exited at 17850 for +$500&#39;)&quot;</p></blockquote><p><strong>Step 2:</strong> Type what happened in plain English. For example:</p><blockquote><p>&quot;Longed NQ at 17500 on the pullback, hit my target at 17600 for +$500. Waited patiently for the setup.&quot;</p></blockquote><p>Or keep it simple:</p><blockquote><p>&quot;Won $300 on ES, followed my plan&quot;</p></blockquote><p>Or honest:</p><blockquote><p>&quot;FOMO&#39;d into a short, knew it was wrong, lost $250&quot;</p></blockquote><p><strong>Step 3:</strong> Press Enter or click &quot;Log Trade.&quot;</p><p><strong>What happens next:</strong></p><ul><li>The input flashes green to confirm your trade was logged</li><li>The text box clears and refocuses automatically</li><li>Your trade appears in the charts above</li><li>The AI reads your description and figures out the details</li></ul><h2 id="what-the-ai-extracts" tabindex="-1">What the AI Extracts <a class="header-anchor" href="#what-the-ai-extracts" aria-label="Permalink to &quot;What the AI Extracts&quot;">​</a></h2><p>When you type a trade description, the AI pulls out:</p><ul><li><strong>Direction</strong> — Long or short</li><li><strong>Outcome</strong> — Win, loss, or breakeven</li><li><strong>P&amp;L</strong> — The dollar amount (or a rough estimate like &quot;small winner&quot; or &quot;nice loss&quot;)</li><li><strong>Discipline score</strong> — Based on how you describe the trade (patience, following rules, or chasing)</li><li><strong>Agency score</strong> — Based on whether you sound in control or reactive</li></ul><p>You do not need to be precise. The system handles approximations like &quot;small winner&quot; or &quot;nice loss.&quot;</p><div class="tip custom-block"><p class="custom-block-title">Do Not Overthink It</p><p>You do not need any special format. All of these work:</p><ul><li>&quot;Long NQ, made $500&quot;</li><li>&quot;Short ES, lost $200, chased the entry&quot;</li><li>&quot;Scratched the trade, no harm done&quot;</li><li>&quot;Revenge traded after the loser, -$400&quot;</li></ul></div><h2 id="after-your-first-trade" tabindex="-1">After Your First Trade <a class="header-anchor" href="#after-your-first-trade" aria-label="Permalink to &quot;After Your First Trade&quot;">​</a></h2><p>Once you log your first trade:</p><ul><li>The P&amp;L chart shows a single point — your cumulative P&amp;L so far</li><li>The Discipline and Agency charts show your first score</li><li>The session stats appear in the Insights panel</li></ul><p>Keep logging trades throughout your session. The more data, the more useful the charts become.</p><h2 id="what-session-means" tabindex="-1">What &quot;Session&quot; Means <a class="header-anchor" href="#what-session-means" aria-label="Permalink to &quot;What &quot;Session&quot; Means&quot;">​</a></h2><p>A session runs from when you start logging trades until you stop for more than 30 minutes. After that idle time, any new trades start a fresh session.</p><p>The system tracks each session separately, so you can look back at past days and see how your sessions went.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you have the basics:</p><ul><li>Learn more about <a href="/help/features/trade-logging">how trade logging works</a></li><li>Understand <a href="/help/features/dashboard">your dashboard charts</a></li><li>Read about <a href="/help/features/ai-insights">AI insights</a></li></ul><p>Happy trading.</p>',40)])])}const g=e(s,[["render",i]]);export{c as __pageData,g as default};
